package cache

import (
	"fmt"
	"sync"
	"testing"
	"time"
)

// DO NOT MODIFY THIS FILE.
// These tests expose bugs in cache.go. Fix the bugs, not the tests.

// TestSetAndGet verifies that entries survive their TTL.
// Fails because the TTL calculation is inverted, causing immediate expiry.
func TestSetAndGet(t *testing.T) {
	c := New(100, 50*time.Millisecond)
	defer c.Stop()

	c.Set("alpha", "one", 2*time.Second)
	c.Set("beta", "two", 2*time.Second)
	c.Set("gamma", "three", 2*time.Second)

	// Entries should still be alive — they have a 2-second TTL.
	for _, tc := range []struct {
		key  string
		want string
	}{
		{"alpha", "one"},
		{"beta", "two"},
		{"gamma", "three"},
	} {
		val, ok := c.Get(tc.key)
		if !ok {
			t.Errorf("Get(%q): expected hit, got miss", tc.key)
			continue
		}
		if val.(string) != tc.want {
			t.Errorf("Get(%q) = %v, want %v", tc.key, val, tc.want)
		}
	}

	stats := c.Stats()
	if stats.Hits != 3 {
		t.Errorf("expected 3 hits, got %d", stats.Hits)
	}
	if stats.Misses != 0 {
		t.Errorf("expected 0 misses, got %d", stats.Misses)
	}
}

// TestConcurrentAccess hammers the cache from multiple goroutines.
// Fails with -race because the background evictor reads without a lock.
func TestConcurrentAccess(t *testing.T) {
	c := New(500, 5*time.Millisecond)
	defer c.Stop()

	var wg sync.WaitGroup
	const workers = 10
	const opsPerWorker = 200

	// Writers
	for w := 0; w < workers; w++ {
		wg.Add(1)
		go func(id int) {
			defer wg.Done()
			for i := 0; i < opsPerWorker; i++ {
				key := fmt.Sprintf("w%d-k%d", id, i)
				c.Set(key, i, 50*time.Millisecond)
			}
		}(w)
	}

	// Readers
	for w := 0; w < workers; w++ {
		wg.Add(1)
		go func(id int) {
			defer wg.Done()
			for i := 0; i < opsPerWorker; i++ {
				key := fmt.Sprintf("w%d-k%d", id, i)
				c.Get(key)
			}
		}(w)
	}

	wg.Wait()

	// Verify stats are consistent: total operations = hits + misses + some evictions.
	stats := c.Stats()
	totalLookups := stats.Hits + stats.Misses
	expectedLookups := int64(workers * opsPerWorker)
	if totalLookups != expectedLookups {
		t.Errorf("expected %d total lookups (hits+misses), got %d (hits=%d, misses=%d)",
			expectedLookups, totalLookups, stats.Hits, stats.Misses)
	}
}

// TestMaxSizeEviction verifies that the cache respects its size limit.
// Fails with a panic or incorrect eviction count due to the race between
// the background evictor and the LRU eviction in Set().
func TestMaxSizeEviction(t *testing.T) {
	const maxSize = 5
	c := New(maxSize, 10*time.Millisecond)
	defer c.Stop()

	// Insert more entries than the cache can hold.
	for i := 0; i < 20; i++ {
		key := fmt.Sprintf("key-%d", i)
		c.Set(key, i, 2*time.Second)
	}

	// Cache should not exceed max size.
	if n := c.Len(); n > maxSize {
		t.Errorf("cache size %d exceeds max %d", n, maxSize)
	}

	// The most recently inserted entries should be present.
	for i := 15; i < 20; i++ {
		key := fmt.Sprintf("key-%d", i)
		val, ok := c.Get(key)
		if !ok {
			t.Errorf("Get(%q): expected hit for recent entry, got miss", key)
			continue
		}
		if val.(int) != i {
			t.Errorf("Get(%q) = %v, want %d", key, val, i)
		}
	}
}

package cache

import (
	"testing"
	"time"
)

// DO NOT MODIFY THIS FILE.
// These tests pass with the current (buggy) code and must continue to pass
// after bug fixes. They exercise functionality not affected by the bugs.

// TestNewCache verifies that the constructor returns a usable cache.
func TestNewCache(t *testing.T) {
	c := New(10, time.Second)
	defer c.Stop()

	if c == nil {
		t.Fatal("New returned nil")
	}
	if c.Len() != 0 {
		t.Errorf("new cache should be empty, got Len() = %d", c.Len())
	}
}

// TestDelete verifies that deleting an entry removes it.
func TestDelete(t *testing.T) {
	c := New(10, time.Hour) // long eviction interval — evictor won't interfere
	defer c.Stop()

	c.Set("x", 42, time.Hour)

	// Delete should return true for existing key.
	if !c.Delete("x") {
		t.Error("Delete returned false for existing key")
	}

	// Delete should return false for missing key.
	if c.Delete("x") {
		t.Error("Delete returned true for already-deleted key")
	}

	if c.Len() != 0 {
		t.Errorf("expected empty cache after delete, got Len() = %d", c.Len())
	}
}

// TestStatsAccessible verifies that the Stats method returns a valid struct.
func TestStatsAccessible(t *testing.T) {
	c := New(10, time.Hour)
	defer c.Stop()

	stats := c.Stats()

	// Fresh cache should have all-zero stats.
	if stats.Hits != 0 || stats.Misses != 0 || stats.Evictions != 0 {
		t.Errorf("fresh cache stats should be zero, got %+v", stats)
	}
}

// TestSetOverwrite verifies that setting the same key twice overwrites the value.
func TestSetOverwrite(t *testing.T) {
	c := New(10, time.Hour)
	defer c.Stop()

	c.Set("dup", "first", time.Hour)
	c.Set("dup", "second", time.Hour)

	if c.Len() != 1 {
		t.Errorf("expected 1 entry after overwrite, got %d", c.Len())
	}
}

// TestDeleteNonexistent verifies that deleting a key that was never set is safe.
func TestDeleteNonexistent(t *testing.T) {
	c := New(10, time.Hour)
	defer c.Stop()

	if c.Delete("ghost") {
		t.Error("Delete returned true for key that was never set")
	}
}

