	c.mu.RLock()
	e, ok := c.items[key]
	c.mu.RUnlock()

	if !ok {
		c.mu.Lock()
		c.stats.Misses++
		c.mu.Unlock()
		return nil, false
	}

	if time.Now().After(e.expiresAt) {
		c.mu.Lock()
		if _, still := c.items[key]; still {
			delete(c.items, key)
			c.order = removeFromOrder(c.order, key)
			c.stats.Evictions++
		}
		c.stats.Misses++
		c.mu.Unlock()
		return nil, false
	}

	c.mu.Lock()
	c.stats.Hits++
	c.mu.Unlock()
	return e.value, true
}

// Set adds or updates a cache entry with the given TTL.
// It correctly computes expiration using time.Now().Add(ttl) and
// protects all mutable state with the write lock.
func (c *Cache) Set(key string, value interface{}, ttl time.Duration) {
	c.mu.Lock()
	defer c.mu.Unlock()

	// Update existing entry without changing its insertion order.
	if existing, ok := c.items[key]; ok {
		existing.value = value
		existing.expiresAt = time.Now().Add(ttl)
		return
	}

	// Evict oldest if at capacity.
	if c.maxSize > 0 && len(c.items) >= c.maxSize {
		c.evictOldest()
	}

	now := time.Now()
	c.items[key] = &entry{
		key:       key,
		value:     value,
		expiresAt: now.Add(ttl),
		createdAt: now,
	}
